```rust
#[test]
fn test_json_schema_validation() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    assert!(corpus.corpus.len() >= 3000);
    assert!(corpus.queries.len() >= 150);
    for q in &corpus.queries {
        for &rel in q.relevants.values() {
            assert!(rel == 1 || rel == 2, "Relevance must be 1 or 2, got {}", rel);
        }
    }
}

#[test]
fn test_document_ids_unique() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    let ids: HashSet<_> = corpus.corpus.iter().map(|d| &d.id).collect();
    assert_eq!(ids.len(), corpus.corpus.len(), "Duplicate document IDs found");
}

#[test]
fn test_query_relevants_reference_valid_docs() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    let doc_ids: HashSet<_> = corpus.corpus.iter().map(|d| d.id.as_str()).collect();
    for q in &corpus.queries {
        for doc_id in q.relevants.keys() {
            assert!(doc_ids.contains(doc_id.as_str()),
                "Query {} references unknown doc {}", q.id, doc_id);
        }
    }
}

#[test]
fn test_query_type_distribution() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    let mut type_counts: HashMap<&str, usize> = HashMap::new();
    for q in &corpus.queries {
        *type_counts.entry(q.query_type.as_str()).or_default() += 1;
    }
    assert!(*type_counts.get("entity").unwrap_or(&0) >= 30);
    assert!(*type_counts.get("temporal").unwrap_or(&0) >= 25);
    assert!(*type_counts.get("topical").unwrap_or(&0) >= 40);
    assert!(*type_counts.get("conversational").unwrap_or(&0) >= 25);
    assert!(*type_counts.get("factual").unwrap_or(&0) >= 30);
}

#[test]
fn test_difficulty_distribution() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    let mut diff_counts: HashMap<&str, usize> = HashMap::new();
    for q in &corpus.queries {
        *diff_counts.entry(q.difficulty.as_str()).or_default() += 1;
    }
    let total = corpus.queries.len() as f64;
    let easy_pct = *diff_counts.get("easy").unwrap_or(&0) as f64 / total;
    let hard_pct = *diff_counts.get("hard").unwrap_or(&0) as f64 / total;
    assert!(easy_pct >= 0.30, "Too few easy queries: {:.0}%", easy_pct * 100.0);
    assert!(hard_pct >= 0.15, "Too few hard queries: {:.0}%", hard_pct * 100.0);
}

#[test]
fn test_cross_validation_splits_cover_all_queries() {
    let corpus = load_corpus("tests/fixtures/benchmark_corpus.json").unwrap();
    let mut seen: HashSet<&str> = HashSet::new();
    for qid in &corpus.splits.dev {
        assert!(seen.insert(qid), "Query {} in multiple splits", qid);
    }
    for qid in &corpus.splits.test {
        assert!(seen.insert(qid), "Query {} in multiple splits", qid);
    }
    assert_eq!(seen.len(), corpus.queries.len(), "Splits don't cover all queries");
