## Binary Quantization Support
```rust
/// Binary quantize: each dimension becomes 1 bit (sign of value)
/// Storage: 768 dims / 8 = 96 bytes per document (vs 3072 for FP32)
pub fn binary_quantize(embedding: &[f32]) -> Vec<u8> {
    embedding.chunks(8).map(|chunk| {
        chunk.iter().enumerate().fold(0u8, |acc, (i, &v)| {
            if v > 0.0 { acc | (1 << i) } else { acc }
        })
    }).collect()
}

/// Hamming distance for binary vectors (much faster than cosine)
pub fn hamming_distance(a: &[u8], b: &[u8]) -> u32 {
    a.iter().zip(b).map(|(x, y)| (x ^ y).count_ones()).sum()
}

/// Two-stage retrieval: binary first-pass → FP32 rescore top-K
pub fn binary_search(
    query: &[f32],
    binary_index: &[Vec<u8>],
    fp32_index: &[Vec<f32>],
    top_k: usize,
    rescore_multiplier: usize, // e.g., 4x
) -> Vec<(usize, f32)> {
    let query_binary = binary_quantize(query);

    // First pass: fast hamming distance on all docs
    let mut candidates: Vec<_> = binary_index.iter().enumerate()
        .map(|(i, doc)| (i, hamming_distance(&query_binary, doc)))
        .collect();
    candidates.sort_by_key(|(_, d)| *d);

    // Rescore top candidates with full FP32 cosine
    let rescore_k = top_k * rescore_multiplier;
    candidates.truncate(rescore_k);

    let mut results: Vec<_> = candidates.iter()
        .map(|(i, _)| (*i, cosine_similarity(query, &fp32_index[*i])))
        .collect();
    results.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    results.truncate(top_k);
    results
}
```

